use strict;
use warnings;

my @todo_list;

sub show_menu {
    print "\n=== YAPILACAKLAR LISTESI ===\n";
    print "1. Gorev Ekle\n";
    print "2. Gorevleri Listele\n";
    print "3. Gorev Sil\n";
    print "4. Cikis\n";
}

sub add_task {
    my ($task) = @_;
    push @todo_list, $task;
    print "Eklendi: '$task'\n";
}

sub list_tasks {
    if (scalar(@todo_list) == 0) {
        print "Liste bos.\n";
        return;
    }

    for my $i (0 .. $#todo_list) {
        my $num = $i + 1;
        print "$num. $todo_list[$i]\n";
    }
}

sub remove_task {
    my ($index) = @_;
    if ($index >= 0 && $index <= $#todo_list) {
        my $removed = splice(@todo_list, $index, 1);
        print "Silindi: '$removed'\n";
    } else {
        print "Gecersiz numara.\n";
    }
}

show_menu();

print "\n> Secim: 1\n";
